import { DEPLOYMENT_CONSTANTS } from "../../constants/deployment-config.js";

export class EcosystemGenerator {
    constructor(remotePath) {
        if (!remotePath) {
            throw new Error("EcosystemGenerator requires remotePath — pass DEPLOYMENT_CONSTANTS.REMOTE_PATH");
        }
        this.remotePath = remotePath;
    }

    generate(env) {
        const discordName = DEPLOYMENT_CONSTANTS.PM2.DISCORD_NAME;
        const serverName = DEPLOYMENT_CONSTANTS.PM2.SERVER_NAME;
        const backendPort = DEPLOYMENT_CONSTANTS.BACKEND_PORT;

        if (!discordName || !serverName || !backendPort) {
            throw new Error(
                "EcosystemGenerator missing required env: DEPLOY_PM2_DISCORD_NAME, DEPLOY_PM2_SERVER_NAME, DEPLOY_BACKEND_PORT",
            );
        }

        const serverEnv = { ...this.buildEnvObject(env), PORT: backendPort, BEHIND_PROXY: "1" };

        const config = {
            apps: [
                {
                    name: discordName,
                    script: "node",
                    args: "--import tsx main/discord/src/index.ts",
                    cwd: this.remotePath,
                    instances: 1,
                    exec_mode: "fork",
                    env: this.buildEnvObject(env),
                    error_file: `${this.remotePath}/logs/discord-error.log`,
                    out_file: `${this.remotePath}/logs/discord-out.log`,
                    time: true,
                    autorestart: true,
                    max_restarts: DEPLOYMENT_CONSTANTS.PM2_MAX_RESTARTS,
                    min_uptime: "10s",
                    watch: false,
                    max_memory_restart: "1G",
                    kill_timeout: 10000,
                    listen_timeout: 10000,
                },
                {
                    name: serverName,
                    script: "node",
                    args: "--import tsx main/server/src/index.ts",
                    cwd: this.remotePath,
                    instances: 1,
                    exec_mode: "fork",
                    env: serverEnv,
                    error_file: `${this.remotePath}/logs/server-error.log`,
                    out_file: `${this.remotePath}/logs/server-out.log`,
                    time: true,
                    autorestart: true,
                    max_restarts: DEPLOYMENT_CONSTANTS.PM2_MAX_RESTARTS,
                    min_uptime: "10s",
                    watch: false,
                    max_memory_restart: "1G",
                    kill_timeout: 10000,
                    listen_timeout: 10000,
                },
            ],
        };

        return this.generateConfigString(config);
    }

    buildEnvObject(env) {
        return {
            NODE_ENV: "production",
            ...env,
        };
    }

    generateConfigString(config) {
        return `// PM2 Ecosystem Configuration — generated by deployment/utils/env/ecosystem-generator.js\n\nmodule.exports = ${JSON.stringify(config, null, 4)};\n`;
    }

    async saveToFile(env, outputPath) {
        const fs = await import("node:fs");
        fs.writeFileSync(outputPath, this.generate(env), "utf8");
    }
}
